mapper.select:
SELECT * FROM chat_messages
WHERE session_id = #{sessionId}
ORDER BY create_time ASC

SELECT * FROM chat_messages
WHERE session_id = #{sessionId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT * FROM chat_messages
WHERE session_id = #{sessionId}
AND content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY create_time DESC
LIMIT #{limit}

SELECT * FROM chat_messages
WHERE session_id = #{sessionId}
AND role = #{role}
AND content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY create_time DESC
LIMIT #{limit}

SELECT * FROM chat_messages
WHERE session_id = #{sessionId}
AND create_time >= #{startTime}
AND create_time <= #{endTime}
ORDER BY create_time DESC
LIMIT #{limit}
